import{_ as t,c as o,o as a,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Mode Ultrawork : Activer toutes les fonctionnalités","description":"Découvrez le mode Ultrawork d'oh-my-opencode pour activer toutes les fonctionnalités avec une seule commande. Active les agents parallèles, l'achèvement forcé et le système Category + Skills.","frontmatter":{"title":"Mode Ultrawork : Activer toutes les fonctionnalités","sidebarTitle":"Mode Ultrawork","subtitle":"Mode Ultrawork : Activer toutes les fonctionnalités avec une seule commande","description":"Découvrez le mode Ultrawork d'oh-my-opencode pour activer toutes les fonctionnalités avec une seule commande. Active les agents parallèles, l'achèvement forcé et le système Category + Skills.","tags":["ultrawork","tâches d'arrière-plan","collaboration d'agents"],"prerequisite":["start-installation","start-sisyphus-orchestrator"],"order":30},"headers":[],"relativePath":"fr/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"fr/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}`),r={name:"fr/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function i(l,e,n,d,c,u){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="mode-ultrawork-activer-toutes-les-fonctionnalites-avec-une-seule-commande" tabindex="-1">Mode Ultrawork : Activer toutes les fonctionnalités avec une seule commande <a class="header-anchor" href="#mode-ultrawork-activer-toutes-les-fonctionnalites-avec-une-seule-commande" aria-label="Permalink to &quot;Mode Ultrawork : Activer toutes les fonctionnalités avec une seule commande&quot;">​</a></h1><h2 id="ce-que-vous-allez-apprendre" tabindex="-1">Ce que vous allez apprendre <a class="header-anchor" href="#ce-que-vous-allez-apprendre" aria-label="Permalink to &quot;Ce que vous allez apprendre&quot;">​</a></h2><ul><li>Activer toutes les fonctionnalités avancées d&#39;oh-my-opencode avec une seule commande</li><li>Faire travailler plusieurs agents IA en parallèle comme une véritable équipe</li><li>Éviter de configurer manuellement plusieurs agents et tâches d&#39;arrière-plan</li><li>Comprendre la philosophie de conception et les meilleures pratiques du mode Ultrawork</li></ul><h2 id="vos-defis-actuels" tabindex="-1">Vos défis actuels <a class="header-anchor" href="#vos-defis-actuels" aria-label="Permalink to &quot;Vos défis actuels&quot;">​</a></h2><p>Vous avez peut-être rencontré ces situations lors du développement :</p><ul><li><strong>Trop de fonctionnalités, ne savez pas comment les utiliser</strong> : Vous avez 10 agents spécialisés, des tâches d&#39;arrière-plan, des outils LSP, mais ne savez pas comment les activer rapidement</li><li><strong>Configuration manuelle requise</strong> : Chaque tâche complexe nécessite de spécifier manuellement les agents, la concurrence d&#39;arrière-plan et autres paramètres</li><li><strong>Collaboration d&#39;agents inefficace</strong> : Appel d&#39;agents en série, gaspillage de temps et de coûts</li><li><strong>Tâches bloquées à mi-chemin</strong> : Les agents n&#39;ont pas assez de motivation et de contraintes pour terminer les tâches</li></ul><p>Tout cela affecte votre capacité à libérer la véritable puissance d&#39;oh-my-opencode.</p><h2 id="concept-de-base" tabindex="-1">Concept de base <a class="header-anchor" href="#concept-de-base" aria-label="Permalink to &quot;Concept de base&quot;">​</a></h2><p><strong>Le Mode Ultrawork</strong> est le mécanisme &quot;activer tout en un clic&quot; d&#39;oh-my-opencode.</p><div class="info custom-block"><p class="custom-block-title">Qu&#39;est-ce que le Mode Ultrawork ?</p><p>Le Mode Ultrawork est un mode de travail spécial déclenché par un mot-clé. Lorsque votre invite contient <code>ultrawork</code> ou son abréviation <code>ulw</code>, le système active automatiquement toutes les fonctionnalités avancées : tâches d&#39;arrière-plan parallèles, exploration approfondie, achèvement forcé, collaboration multi-agents, et plus encore.</p></div><h3 id="philosophie-de-conception" tabindex="-1">Philosophie de conception <a class="header-anchor" href="#philosophie-de-conception" aria-label="Permalink to &quot;Philosophie de conception&quot;">​</a></h3><p>Le mode Ultrawork repose sur les principes fondamentaux suivants (tirés du <a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Manifeste Ultrawork</a>) :</p><table tabindex="0"><thead><tr><th>Principe</th><th>Description</th></tr></thead><tbody><tr><td><strong>L&#39;intervention humaine est un signal d&#39;échec</strong></td><td>Si vous devez constamment corriger la sortie de l&#39;IA, cela signifie qu&#39;il y a un problème avec la conception du système</td></tr><tr><td><strong>Code indiscernable</strong></td><td>Le code écrit par l&#39;IA doit être indiscernable du code écrit par des ingénieurs seniors</td></tr><tr><td><strong>Minimiser la charge cognitive</strong></td><td>Vous devez seulement dire &quot;quoi faire&quot;, les agents sont responsables du &quot;comment faire&quot;</td></tr><tr><td><strong>Prévisible, cohérent, délégable</strong></td><td>Les agents doivent être aussi stables et fiables qu&#39;un compilateur</td></tr></tbody></table><h3 id="mecanisme-d-activation" tabindex="-1">Mécanisme d&#39;activation <a class="header-anchor" href="#mecanisme-d-activation" aria-label="Permalink to &quot;Mécanisme d&#39;activation&quot;">​</a></h3><p>Lorsque le système détecte le mot-clé <code>ultrawork</code> ou <code>ulw</code> :</p><ol><li><strong>Définir le mode de précision maximale</strong> : <code>message.variant = &quot;max&quot;</code></li><li><strong>Afficher la notification Toast</strong> : &quot;Mode Ultrawork Activé - Précision maximale engagée. Tous les agents à votre disposition.&quot;</li><li><strong>Injecter des instructions complètes</strong> : Injecter 200+ lignes d&#39;instructions ULTRAWORK aux agents, notamment : <ul><li>Exiger 100% de certitude avant de commencer l&#39;implémentation</li><li>Exiger l&#39;utilisation parallèle de tâches d&#39;arrière-plan</li><li>Forcer l&#39;utilisation du système Category + Skills</li><li>Forcer la vérification d&#39;achèvement (workflow TDD)</li><li>Interdire toute excuse &quot;je ne peux pas le faire&quot;</li></ul></li></ol><h2 id="suivez-le-guide" tabindex="-1">Suivez le guide <a class="header-anchor" href="#suivez-le-guide" aria-label="Permalink to &quot;Suivez le guide&quot;">​</a></h2><h3 id="etape-1-declencher-le-mode-ultrawork" tabindex="-1">Étape 1 : Déclencher le Mode Ultrawork <a class="header-anchor" href="#etape-1-declencher-le-mode-ultrawork" aria-label="Permalink to &quot;Étape 1 : Déclencher le Mode Ultrawork&quot;">​</a></h3><p>Entrez une invite contenant le mot-clé <code>ultrawork</code> ou <code>ulw</code> dans OpenCode :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork développer une API REST</span></span></code></pre></div><p>Ou plus simplement :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw ajouter l&#39;authentification utilisateur</span></span></code></pre></div><p><strong>Vous devriez voir</strong> :</p><ul><li>Une notification Toast apparaît sur l&#39;interface : &quot;Mode Ultrawork Activé&quot;</li><li>La réponse de l&#39;agent commence par &quot;ULTRAWORK MODE ENABLED!&quot;</li></ul><h3 id="etape-2-observer-les-changements-de-comportement-des-agents" tabindex="-1">Étape 2 : Observer les changements de comportement des agents <a class="header-anchor" href="#etape-2-observer-les-changements-de-comportement-des-agents" aria-label="Permalink to &quot;Étape 2 : Observer les changements de comportement des agents&quot;">​</a></h3><p>Après avoir activé le mode Ultrawork, les agents vont :</p><ol><li><p><strong>Exploration parallèle de la base de code</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;trouver les modèles API existants&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;trouver l&#39;infrastructure de test&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;trouver les meilleures pratiques d&#39;authentification&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>Appeler l&#39;agent Plan pour créer un plan de travail</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;créer un plan détaillé basé sur le contexte rassemblé&quot;)</span></span></code></pre></div></li><li><p><strong>Utiliser Category + Skills pour exécuter les tâches</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>Vous devriez voir</strong> :</p><ul><li>Plusieurs tâches d&#39;arrière-plan s&#39;exécutant simultanément</li><li>Des agents appelant activement des agents spécialisés (Oracle, Librarian, Explore)</li><li>Des plans de test complets et une décomposition du travail</li><li>Les tâches continuent de s&#39;exécuter jusqu&#39;à 100% d&#39;achèvement</li></ul><h3 id="etape-3-verifier-l-achevement-des-taches" tabindex="-1">Étape 3 : Vérifier l&#39;achèvement des tâches <a class="header-anchor" href="#etape-3-verifier-l-achevement-des-taches" aria-label="Permalink to &quot;Étape 3 : Vérifier l&#39;achèvement des tâches&quot;">​</a></h3><p>Une fois les agents terminés, ils vont :</p><ol><li><strong>Afficher afficher les preuves de vérification</strong> : Sortie de test réelle, descriptions de vérification manuelle</li><li><strong>Confirmer que tous les TODO sont terminés</strong> : Ne déclarent pas l&#39;achèvement prématurément</li><li><strong>Résumer le travail effectué</strong> : Lister ce qui a été fait et pourquoi</li></ol><p><strong>Vous devriez voir</strong> :</p><ul><li>Des résultats de test clairs (pas &quot;devrait fonctionner&quot;)</li><li>Tous les problèmes résolus</li><li>Aucune liste de TODO inachevée</li></ul><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><p>Après avoir terminé les étapes ci-dessus, confirmez :</p><ul><li>[ ] Vous voyez une notification Toast après avoir entré <code>ulw</code></li><li>[ ] La réponse de l&#39;agent commence par &quot;ULTRAWORK MODE ENABLED!&quot;</li><li>[ ] Vous observez des tâches d&#39;arrière-plan parallèles en cours d&#39;exécution</li><li>[ ] Les agents utilisent le système Category + Skills</li><li>[ ] Il y a des preuves de vérification après l&#39;achèvement des tâches</li></ul><p>Si un élément échoue, vérifiez :</p><ul><li>L&#39;orthographe du mot-clé est-elle correcte (<code>ultrawork</code> ou <code>ulw</code>)</li><li>Êtes-vous dans la session principale (les tâches d&#39;arrière-plan ne déclencheront pas le mode)</li><li>Le fichier de configuration est-il activé avec les fonctionnalités pertinentes</li></ul><h2 id="quand-utiliser-cette-technique" tabindex="-1">Quand utiliser cette technique <a class="header-anchor" href="#quand-utiliser-cette-technique" aria-label="Permalink to &quot;Quand utiliser cette technique&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scénario</th><th>Utiliser Ultrawork</th><th>Mode normal</th></tr></thead><tbody><tr><td><strong>Nouvelles fonctionnalités complexes</strong></td><td>✅ Recommandé (nécessite une collaboration multi-agents)</td><td>❌ Peut ne pas être assez efficace</td></tr><tr><td><strong>Corrections urgentes</strong></td><td>✅ Recommandé (nécessite un diagnostic rapide et une exploration)</td><td>❌ Peut manquer de contexte</td></tr><tr><td><strong>Modifications simples</strong></td><td>❌ Excessif (gaspille des ressources)</td><td>✅ Plus adapté</td></tr><tr><td><strong>Validation rapide d&#39;idée</strong></td><td>❌ Excessif</td><td>✅ Plus adapté</td></tr></tbody></table><p><strong>Règle empirique</strong> :</p><ul><li>La tâche implique plusieurs modules ou systèmes → Utilisez <code>ulw</code></li><li>Besoin d&#39;une recherche approfondie de la base de code → Utilisez <code>ulw</code></li><li>Besoin d&#39;appeler plusieurs agents spécialisés → Utilisez <code>ulw</code></li><li>Modification simple d&#39;un seul fichier → Pas besoin de <code>ulw</code></li></ul><h2 id="pieges-courants" tabindex="-1">Pièges courants <a class="header-anchor" href="#pieges-courants" aria-label="Permalink to &quot;Pièges courants&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Notes importantes</p><p><strong>1. N&#39;utilisez pas <code>ulw</code> dans chaque invite</strong></p><p>Le mode Ultrawork injecte une grande quantité d&#39;instructions, ce qui est excessif pour les tâches simples. Utilisez-le uniquement pour les tâches complexes qui nécessitent véritablement une collaboration multi-agents, une exploration parallèle et une analyse approfondie.</p><p><strong>2. Les tâches d&#39;arrière-plan ne déclenchent pas le mode Ultrawork</strong></p><p>Le détecteur de mots-clés ignore les sessions d&#39;arrière-plan pour éviter d&#39;injecter incorrectement le mode dans les sous-agents. Le mode Ultrawork ne fonctionne que dans la session principale.</p><p><strong>3. Assurez-vous que la configuration Provider est correcte</strong></p><p>Le mode Ultrawork repose sur plusieurs modèles IA travaillant en parallèle. Si certains Providers ne sont pas configurés ou indisponibles, les agents peuvent ne pas être en mesure d&#39;appeler des agents spécialisés.</p></div><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la leçon&quot;">​</a></h2><p>Le mode Ultrawork atteint l&#39;objectif de conception &quot;activer toutes les fonctionnalités avec une seule commande&quot; grâce au déclenchement par mot-clé :</p><ul><li><strong>Facile à utiliser</strong> : Entrez simplement <code>ulw</code> pour activer</li><li><strong>Collaboration automatique</strong> : Les agents appellent automatiquement d&#39;autres agents et exécutent des tâches d&#39;arrière-plan en parallèle</li><li><strong>Achèvement forcé</strong> : Le mécanisme de vérification complète garantit 100% d&#39;achèvement</li><li><strong>Zéro configuration</strong> : Pas besoin de définir manuellement les priorités des agents, les limites de concurrence, etc.</li></ul><p>Rappelez-vous : le mode Ultrawork est conçu pour faire travailler les agents comme une véritable équipe. Vous devez seulement exprimer l&#39;intention, les agents sont responsables de l&#39;exécution.</p><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la prochaine leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la prochaine leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous apprendrons <strong><a href="./../../platforms/provider-setup/">Configuration Provider</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Comment configurer plusieurs Providers comme Anthropic, OpenAI, Google</li><li>Comment la stratégie multi-modèles dégrade automatiquement et sélectionne les modèles optimaux</li><li>Comment tester les connexions Provider et l&#39;utilisation des quotas</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour développer les emplacements du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Numéros de ligne</th></tr></thead><tbody><tr><td>Philosophie de conception Ultrawork</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer"><code>docs/ultrawork-manifesto.md</code></a></td><td>1-198</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Modèle d&#39;instruction ULTRAWORK</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/constants.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/constants.ts</code></a></td><td>54-280</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>KEYWORD_DETECTORS</code> : Configuration du détecteur de mots-clés, incluant trois modes : ultrawork, search, analyze</li><li><code>CODE_BLOCK_PATTERN</code> : Motif regex de bloc de code, utilisé pour filtrer les mots-clés dans les blocs de code</li><li><code>INLINE_CODE_PATTERN</code> : Motif regex de code en ligne, utilisé pour filtrer les mots-clés dans le code en ligne</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>createKeywordDetectorHook()</code> : Crée le Hook détecteur de mots-clés, écoute l&#39;événement UserPromptSubmit</li><li><code>detectKeywordsWithType()</code> : Détecte les mots-clés dans le texte et retourne le type (ultrawork/search/analyze)</li><li><code>getUltraworkMessage()</code> : Génère les instructions complètes du mode ULTRAWORK (sélectionne Planner ou mode normal selon le type d&#39;agent)</li><li><code>removeCodeBlocks()</code> : Supprime les blocs de code du texte pour éviter de déclencher des mots-clés dans les blocs de code</li></ul><p><strong>Règles métier</strong> :</p><table tabindex="0"><thead><tr><th>ID de règle</th><th>Description de la règle</th><th>Tag</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>Activer le mode Ultrawork lorsque &quot;ultrawork&quot; ou &quot;ulw&quot; est détecté</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-2</td><td>Le mode Ultrawork définit <code>message.variant = &quot;max&quot;</code></td><td>[Fact]</td></tr><tr><td>BR-4.8.4-3</td><td>Le mode Ultrawork affiche la notification Toast : &quot;Mode Ultrawork Activé&quot;</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-4</td><td>Les sessions de tâches d&#39;arrière-plan ignorent la détection de mots-clés pour éviter l&#39;injection de mode</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-5</td><td>Les sessions non principales n&#39;autorisent que le mot-clé ultrawork, bloquant l&#39;injection d&#39;autres modes</td><td>[Fact]</td></tr></tbody></table></details>`,54)])])}const h=t(r,[["render",i]]);export{m as __pageData,h as default};
